import axios from 'axios';

const api = axios.create({
  baseURL: '/api',
  timeout: 10000,
});

// Request interceptor
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Response interceptor
api.interceptors.response.use(
  (response) => response.data,
  (error) => {
    if (error.response?.status === 401) {
      localStorage.removeItem('token');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

// Settings API
export const getSettings = () => api.get('/settings');
export const updateSettings = (data) => api.put('/settings', data);

// Rules API
export const getRules = () => api.get('/rules');
export const updateRule = (id, data) => api.put(`/rules/${id}`, data);
export const createRule = (data) => api.post('/rules', data);
export const deleteRule = (id) => api.delete(`/rules/${id}`);

// Nodes API
export const getNodes = () => api.get('/nodes');
export const getNodeStatus = (id) => api.get(`/nodes/${id}/status`);
export const updateNode = (id, data) => api.put(`/nodes/${id}`, data);
export const deleteNode = (id) => api.delete(`/nodes/${id}`);

// Subscriptions API
export const getSubscriptions = () => api.get('/subscriptions');
export const updateSubscription = (id, data) => api.put(`/subscriptions/${id}`, data);
export const createSubscription = (data) => api.post('/subscriptions', data);
export const deleteSubscription = (id) => api.delete(`/subscriptions/${id}`);
export const refreshSubscription = (id) => api.post(`/subscriptions/${id}/refresh`);

// System API
export const getSystemInfo = () => api.get('/system/info');
export const getSystemStatus = () => api.get('/system/status');
export const restartService = () => api.post('/system/restart');

export default api;
